    table_stack = []
    i = 0
    while i < len(html):
      if html[i] === '<':
        tag = html.slice(i + 1, html.index('>', i))
        if tag === 'table':
          table_stack.append(tag)
        if tag === 'tr':
          table_stack.append(tag)
        if tag === 'td':
          if len(table_stack) > 0 and table_stack[-1] === 'tr':
            table_stack.append(tag)
      i += html.index('>', i) - i + 1
    output = ''
    while table_stack:
      output += '</' + table_stack.pop() + '>
'
    return output

  def main(self):
    html = self.read_input()
    output = self.fix_table_tags(html)
